defmodule WebhookProxyWeb.ProxyController do
  use WebhookProxyWeb, :controller

  require Logger

  def fetch(conn, %{"url" => url}) do
    case validate_url(url) do
      {:ok, validated_url} ->
        case HTTPoison.get(validated_url, [], follow_redirect: true, max_redirect: 5, timeout: 10_000, recv_timeout: 10_000) do
          {:ok, %HTTPoison.Response{status_code: status_code, body: body, headers: headers}} when status_code in 200..299 ->
            content_type = get_content_type(headers)

            conn
            |> put_status(200)
            |> json(%{
              status: status_code,
              content_type: content_type,
              body: body,
              url: validated_url
            })

          {:ok, %HTTPoison.Response{status_code: status_code, body: body}} ->
            conn
            |> put_status(502)
            |> json(%{
              error: "Upstream server returned an error",
              upstream_status: status_code,
              body: body,
              url: validated_url
            })

          {:error, %HTTPoison.Error{reason: reason}} ->
            Logger.error("Failed to fetch URL #{validated_url}: #{inspect(reason)}")

            conn
            |> put_status(502)
            |> json(%{
              error: "Failed to fetch the requested URL",
              reason: to_string(reason),
              url: validated_url
            })
        end

      {:error, reason} ->
        conn
        |> put_status(400)
        |> json(%{error: "Invalid URL", reason: reason})
    end
  end

  def fetch(conn, _params) do
    conn
    |> put_status(400)
    |> json(%{error: "Missing required parameter: url"})
  end

  defp validate_url(url) when is_binary(url) do
    uri = URI.parse(url)

    cond do
      uri.scheme not in ["http", "https"] ->
        {:error, "URL must use http or https scheme"}

      is_nil(uri.host) or uri.host == "" ->
        {:error, "URL must contain a valid host"}

      blocked_host?(uri.host) ->
        {:error, "Access to the specified host is not allowed"}

      true ->
        {:ok, url}
    end
  end

  defp validate_url(_), do: {:error, "URL must be a string"}

  defp blocked_host?(host) do
    blocked_patterns = [
      "localhost",
      "127.0.0.1",
      "0.0.0.0",
      "::1",
      "169.254.",
      "10.",
      "172.16.",
      "172.17.",
      "172.18.",
      "172.19.",
      "172.20.",
      "172.21.",
      "172.22.",
      "172.23.",
      "172.24.",
      "172.25.",
      "172.26.",
      "172.27.",
      "172.28.",
      "172.29.",
      "172.30.",
      "172.31.",
      "192.168."
    ]

    Enum.any?(blocked_patterns, fn pattern ->
      String.starts_with?(host, pattern) or host == pattern
    end)
  end

  defp get_content_type(headers) do
    headers
    |> Enum.find(fn {key, _value} -> String.downcase(key) == "content-type" end)
    |> case do
      {_key, value} -> value
      nil -> "application/octet-stream"
    end
  end
